package com.dataprocessing.fileservice;

import io.grpc.stub.StreamObserver;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.*;
import java.nio.file.*;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;

public class FileServiceImpl extends FileServiceGrpc.FileServiceImplBase {

    private static final Logger logger = LoggerFactory.getLogger(FileServiceImpl.class);
    private static final String UPLOAD_DIR = "/tmp/uploads/";
    private static final int DOWNLOAD_CHUNK_SIZE = 1024 * 1024; // 1MB chunks

    private final ConcurrentHashMap<String, AtomicLong> uploadProgress = new ConcurrentHashMap<>();
    private final ConcurrentHashMap<String, StreamObserver<ProcessingMessage>> activeSessions = new ConcurrentHashMap<>();

    public FileServiceImpl() {
        try {
            Files.createDirectories(Paths.get(UPLOAD_DIR));
        } catch (IOException e) {
            logger.error("Failed to create upload directory", e);
        }
    }

    // Client streaming RPC - file upload
    @Override
    public StreamObserver<FileChunk> uploadFile(StreamObserver<UploadStatus> responseObserver) {
        return new StreamObserver<FileChunk>() {
            private String filename;
            private OutputStream outputStream;
            private long totalBytesReceived = 0;
            private boolean hasError = false;

            @Override
            public void onNext(FileChunk chunk) {
                try {
                    if (filename == null) {
                        filename = chunk.getFilename();
                        if (filename == null || filename.isEmpty()) {
                            throw new IllegalArgumentException("Filename is required in the first chunk");
                        }
                        // Sanitize filename to prevent path traversal
                        filename = Paths.get(filename).getFileName().toString();
                        Path filePath = Paths.get(UPLOAD_DIR, filename);
                        outputStream = new BufferedOutputStream(new FileOutputStream(filePath.toFile()));
                        uploadProgress.put(filename, new AtomicLong(0));
                        logger.info("Starting upload for file: {}, expected size: {}", filename, chunk.getTotalSize());

                        if (chunk.getMetadataMap() != null && !chunk.getMetadataMap().isEmpty()) {
                            logger.info("File metadata: {}", chunk.getMetadataMap());
                        }
                    }

                    byte[] data = chunk.getContent().toByteArray();
                    outputStream.write(data);
                    totalBytesReceived += data.length;
                    uploadProgress.get(filename).set(totalBytesReceived);

                    logger.debug("Received chunk for {}: {} bytes (total: {})",
                            filename, data.length, totalBytesReceived);

                } catch (Exception e) {
                    hasError = true;
                    logger.error("Error processing chunk for file: {}", filename, e);
                    responseObserver.onNext(UploadStatus.newBuilder()
                            .setFilename(filename != null ? filename : "unknown")
                            .setSuccess(false)
                            .setMessage("Upload failed: " + e.getMessage())
                            .setBytesReceived(totalBytesReceived)
                            .build());
                    responseObserver.onCompleted();
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.error("Upload stream error for file: {}", filename, t);
                cleanup();
                if (filename != null) {
                    uploadProgress.remove(filename);
                    try {
                        Files.deleteIfExists(Paths.get(UPLOAD_DIR, filename));
                    } catch (IOException e) {
                        logger.error("Failed to clean up partial upload: {}", filename, e);
                    }
                }
            }

            @Override
            public void onCompleted() {
                cleanup();
                if (!hasError) {
                    logger.info("Upload completed for file: {}, total bytes: {}", filename, totalBytesReceived);
                    responseObserver.onNext(UploadStatus.newBuilder()
                            .setFilename(filename != null ? filename : "unknown")
                            .setSuccess(true)
                            .setMessage("Upload completed successfully")
                            .setBytesReceived(totalBytesReceived)
                            .build());
                    responseObserver.onCompleted();
                }
                if (filename != null) {
                    uploadProgress.remove(filename);
                }
            }

            private void cleanup() {
                if (outputStream != null) {
                    try {
                        outputStream.flush();
                        outputStream.close();
                    } catch (IOException e) {
                        logger.error("Error closing output stream", e);
                    }
                }
            }
        };
    }

    // Server streaming RPC - file download / large data transfer
    @Override
    public void downloadFile(DataRequest request, StreamObserver<DataResponse> responseObserver) {
        String queryId = request.getQueryId();
        String query = request.getQuery();
        logger.info("Download request - queryId: {}, query: {}", queryId, query);

        try {
            // Sanitize the query to prevent path traversal
            String sanitizedFilename = Paths.get(query).getFileName().toString();
            Path filePath = Paths.get(UPLOAD_DIR, sanitizedFilename);

            if (!Files.exists(filePath)) {
                responseObserver.onNext(DataResponse.newBuilder()
                        .setQueryId(queryId)
                        .setSequenceNumber(0)
                        .setIsLast(true)
                        .setStatus("FILE_NOT_FOUND")
                        .build());
                responseObserver.onCompleted();
                return;
            }

            long fileSize = Files.size(filePath);
            long sequenceNumber = 0;

            try (InputStream inputStream = new BufferedInputStream(new FileInputStream(filePath.toFile()))) {
                byte[] buffer = new byte[DOWNLOAD_CHUNK_SIZE];
                int bytesRead;
                long totalSent = 0;

                while ((bytesRead = inputStream.read(buffer)) != -1) {
                    totalSent += bytesRead;
                    boolean isLast = totalSent >= fileSize;

                    DataResponse response = DataResponse.newBuilder()
                            .setQueryId(queryId)
                            .setPayload(com.google.protobuf.ByteString.copyFrom(buffer, 0, bytesRead))
                            .setSequenceNumber(sequenceNumber++)
                            .setIsLast(isLast)
                            .setStatus("OK")
                            .build();

                    responseObserver.onNext(response);
                    logger.debug("Sent chunk {} for queryId: {}, bytes: {}", sequenceNumber - 1, queryId, bytesRead);
                }
            }

            responseObserver.onCompleted();
            logger.info("Download completed for queryId: {}, total chunks: {}", queryId, sequenceNumber);

        } catch (Exception e) {
            logger.error("Error during download for queryId: {}", queryId, e);
            responseObserver.onNext(DataResponse.newBuilder()
                    .setQueryId(queryId)
                    .setSequenceNumber(0)
                    .setIsLast(true)
                    .setStatus("ERROR: " + e.getMessage())
                    .build());
            responseObserver.onCompleted();
        }
    }

    // Bidirectional streaming RPC - data processing pipeline
    @Override
    public StreamObserver<ProcessingMessage> processData(StreamObserver<ProcessingMessage> responseObserver) {
        return new StreamObserver<ProcessingMessage>() {
            private String sessionId;

            @Override
            public void onNext(ProcessingMessage message) {
                try {
                    if (sessionId == null) {
                        sessionId = message.getSessionId();
                        activeSessions.put(sessionId, responseObserver);
                        logger.info("New processing session started: {}", sessionId);
                    }

                    String messageType = message.getMessageType();
                    logger.debug("Processing message - session: {}, type: {}, size: {} bytes",
                            sessionId, messageType, message.getData().size());

                    switch (messageType) {
                        case "TRANSFORM":
                            handleTransform(message, responseObserver);
                            break;
                        case "AGGREGATE":
                            handleAggregate(message, responseObserver);
                            break;
                        case "FILTER":
                            handleFilter(message, responseObserver);
                            break;
                        case "PING":
                            handlePing(message, responseObserver);
                            break;
                        default:
                            handleDefault(message, responseObserver);
                            break;
                    }

                } catch (Exception e) {
                    logger.error("Error processing message in session: {}", sessionId, e);
                    sendErrorResponse(responseObserver, message, e);
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.error("Stream error in session: {}", sessionId, t);
                if (sessionId != null) {
                    activeSessions.remove(sessionId);
                }
            }

            @Override
            public void onCompleted() {
                logger.info("Processing session completed: {}", sessionId);
                if (sessionId != null) {
                    activeSessions.remove(sessionId);
                }

                // Send final acknowledgment
                responseObserver.onNext(ProcessingMessage.newBuilder()
                        .setSessionId(sessionId != null ? sessionId : "unknown")
                        .setMessageType("SESSION_COMPLETE")
                        .setTimestamp(System.currentTimeMillis())
                        .putHeaders("status", "completed")
                        .build());
                responseObserver.onCompleted();
            }
        };
    }

    private void handleTransform(ProcessingMessage message, StreamObserver<ProcessingMessage> responseObserver) {
        byte[] inputData = message.getData().toByteArray();
        // Example transformation: reverse the bytes (placeholder for real processing)
        byte[] transformed = new byte[inputData.length];
        for (int i = 0; i < inputData.length; i++) {
            transformed[i] = inputData[inputData.length - 1 - i];
        }

        ProcessingMessage response = ProcessingMessage.newBuilder()
                .setSessionId(message.getSessionId())
                .setMessageType("TRANSFORM_RESULT")
                .setData(com.google.protobuf.ByteString.copyFrom(transformed))
                .setTimestamp(System.currentTimeMillis())
                .putHeaders("original_size", String.valueOf(inputData.length))
                .putHeaders("result_size", String.valueOf(transformed.length))
                .putAllHeaders(message.getHeadersMap())
                .build();

        responseObserver.onNext(response);
    }

    private void handleAggregate(ProcessingMessage message, StreamObserver<ProcessingMessage> responseObserver) {
        byte[] inputData = message.getData().toByteArray();

        // Example aggregation: compute checksum
        long checksum = 0;
        for (byte b : inputData) {
            checksum += (b & 0xFF);
        }

        String resultJson = String.format("{\"checksum\":%d,\"size\":%d,\"timestamp\":%d}",
                checksum, inputData.length, System.currentTimeMillis());

        ProcessingMessage response = ProcessingMessage.newBuilder()
                .setSessionId(message.getSessionId())
                .setMessageType("AGGREGATE_RESULT")
                .setData(com.google.protobuf.ByteString.copyFromUtf8(resultJson))
                .setTimestamp(System.currentTimeMillis())
                .putHeaders("aggregation_type", "checksum")
                .build();

        responseObserver.onNext(response);
    }

    private void handleFilter(ProcessingMessage message, StreamObserver<ProcessingMessage> responseObserver) {
        byte[] inputData = message.getData().toByteArray();
        Map<String, String> headers = message.getHeadersMap();
        int threshold = Integer.parseInt(headers.getOrDefault("threshold", "128"));

        // Example filter: keep only bytes above threshold
        ByteArrayOutputStream filtered = new ByteArrayOutputStream();
        for (byte b : inputData) {
            if ((b & 0xFF) > threshold) {
                filtered.write(b);
            }
        }

        ProcessingMessage response = ProcessingMessage.newBuilder()
                .setSessionId(message.getSessionId())
                .setMessageType("FILTER_RESULT")
                .setData(com.google.protobuf.ByteString.copyFrom(filtered.toByteArray()))
                .setTimestamp(System.currentTimeMillis())
                .putHeaders("original_count", String.valueOf(inputData.length))
                .putHeaders("filtered_count", String.valueOf(filtered.size()))
                .putHeaders("threshold", String.valueOf(threshold))
                .build();

        responseObserver.onNext(response);
    }

    private void handlePing(ProcessingMessage message, StreamObserver<ProcessingMessage> responseObserver) {
        ProcessingMessage response = ProcessingMessage.newBuilder()
                .setSessionId(message.getSessionId())
                .setMessageType("PONG")
                .setTimestamp(System.currentTimeMillis())
                .putHeaders("server_time", String.valueOf(System.currentTimeMillis()))
                .putHeaders("active_sessions", String.valueOf(activeSessions.size()))
                .build();

        responseObserver.onNext(response);
    }

    private void handleDefault(ProcessingMessage message, StreamObserver<ProcessingMessage> responseObserver) {
        ProcessingMessage response = ProcessingMessage.newBuilder()
                .setSessionId(message.getSessionId())
                .setMessageType("ACK")
                .setTimestamp(System.currentTimeMillis())
                .putHeaders("received_type", message.getMessageType())
                .putHeaders("received_size", String.valueOf(message.getData().size()))
                .build();

        responseObserver.onNext(response);
    }

    private void sendErrorResponse(StreamObserver<ProcessingMessage> responseObserver,
                                   ProcessingMessage originalMessage, Exception e) {
        ProcessingMessage errorResponse = ProcessingMessage.newBuilder()
                .setSessionId(originalMessage.getSessionId())
                .setMessageType("ERROR")
                .setData(com.google.protobuf.ByteString.copyFromUtf8(e.getMessage()))
                .setTimestamp(System.currentTimeMillis())
                .putHeaders("error_class", e.getClass().getSimpleName())
                .putHeaders("original_message_type", originalMessage.getMessageType())
                .build();

        responseObserver.onNext(errorResponse);
    }
}


