package com.dataprocessing.fileservice;

import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.netty.shaded.io.grpc.netty.NettyServerBuilder;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.IOException;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;

public class FileServiceServer {

    private static final Logger logger = LoggerFactory.getLogger(FileServiceServer.class);
    private static final int PORT = 9090;
    // WARNING: Setting maxInboundMessageSize to MAX_VALUE removes message size limits.
    // This can expose the server to resource exhaustion attacks where a malicious client
    // sends extremely large messages to consume all available memory.
    // In production, set this to a reasonable maximum based on your largest expected message.
    // For example: 256 * 1024 * 1024 (256MB) for large file chunks.
    private static final int MAX_MESSAGE_SIZE = Integer.MAX_VALUE;

    private Server server;

    public void start() throws IOException {
        server = NettyServerBuilder.forPort(PORT)
                .addService(new FileServiceImpl())
                .maxInboundMessageSize(MAX_MESSAGE_SIZE)
                .maxInboundMetadataSize(16 * 1024 * 1024) // 16MB metadata
                .executor(Executors.newFixedThreadPool(
                        Runtime.getRuntime().availableProcessors() * 2))
                .keepAliveTime(5, TimeUnit.MINUTES)
                .keepAliveTimeout(20, TimeUnit.SECONDS)
                .permitKeepAliveTime(1, TimeUnit.MINUTES)
                .permitKeepAliveWithoutCalls(true)
                .maxConcurrentCallsPerConnection(100)
                .build()
                .start();

        logger.info("FileService gRPC server started on port {}", PORT);
        logger.info("Max inbound message size: {} bytes", MAX_MESSAGE_SIZE);

        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            logger.info("Shutting down gRPC server...");
            try {
                FileServiceServer.this.stop();
            } catch (InterruptedException e) {
                logger.error("Error during shutdown", e);
                Thread.currentThread().interrupt();
            }
            logger.info("Server shut down.");
        }));
    }

    public void stop() throws InterruptedException {
        if (server != null) {
            server.shutdown().awaitTermination(30, TimeUnit.SECONDS);
        }
    }

    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        FileServiceServer server = new FileServiceServer();
        server.start();
        server.blockUntilShutdown();
    }
}


