package com.dataprocessing.fileservice;

import com.google.protobuf.ByteString;
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.stub.StreamObserver;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.*;
import java.nio.file.*;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;

public class FileServiceClient {

    private static final Logger logger = LoggerFactory.getLogger(FileServiceClient.class);
    private static final int CHUNK_SIZE = 1024 * 1024; // 1MB chunks
    private static final int MAX_MESSAGE_SIZE = Integer.MAX_VALUE;

    private final ManagedChannel channel;
    private final FileServiceGrpc.FileServiceStub asyncStub;
    private final FileServiceGrpc.FileServiceBlockingStub blockingStub;

    public FileServiceClient(String host, int port) {
        channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext()
                .maxInboundMessageSize(MAX_MESSAGE_SIZE)
                .keepAliveTime(5, TimeUnit.MINUTES)
                .keepAliveTimeout(20, TimeUnit.SECONDS)
                .build();

        asyncStub = FileServiceGrpc.newStub(channel)
                .withMaxInboundMessageSize(MAX_MESSAGE_SIZE)
                .withMaxOutboundMessageSize(MAX_MESSAGE_SIZE);
        blockingStub = FileServiceGrpc.newBlockingStub(channel);
    }

    // Client streaming - upload file
    public void uploadFile(String filePath) throws InterruptedException, IOException {
        CountDownLatch latch = new CountDownLatch(1);
        Path path = Paths.get(filePath);
        String filename = path.getFileName().toString();
        long fileSize = Files.size(path);

        logger.info("Starting upload of file: {} ({} bytes)", filename, fileSize);

        StreamObserver<UploadStatus> responseObserver = new StreamObserver<UploadStatus>() {
            @Override
            public void onNext(UploadStatus status) {
                logger.info("Upload status - file: {}, success: {}, message: {}, bytes received: {}",
                        status.getFilename(), status.getSuccess(),
                        status.getMessage(), status.getBytesReceived());
            }

            @Override
            public void onError(Throwable t) {
                logger.error("Upload failed", t);
                latch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info("Upload stream completed");
                latch.countDown();
            }
        };

        StreamObserver<FileChunk> requestObserver = asyncStub.uploadFile(responseObserver);

        try (InputStream inputStream = new BufferedInputStream(new FileInputStream(path.toFile()))) {
            byte[] buffer = new byte[CHUNK_SIZE];
            int bytesRead;
            long offset = 0;

            while ((bytesRead = inputStream.read(buffer)) != -1) {
                FileChunk chunk = FileChunk.newBuilder()
                        .setFilename(filename)
                        .setContent(ByteString.copyFrom(buffer, 0, bytesRead))
                        .setOffset(offset)
                        .setTotalSize(fileSize)
                        .putMetadata("content_type", "application/octet-stream")
                        .build();

                requestObserver.onNext(chunk);
                offset += bytesRead;

                logger.debug("Sent chunk: offset={}, size={}", offset - bytesRead, bytesRead);
            }

            requestObserver.onCompleted();
        } catch (Exception e) {
            requestObserver.onError(e);
            throw e;
        }

        if (!latch.await(5, TimeUnit.MINUTES)) {
            logger.warn("Upload timed out");
        }
    }

    // Server streaming - download file
    public void downloadFile(String queryId, String filename, String outputPath) throws InterruptedException {
        CountDownLatch latch = new CountDownLatch(1);

        DataRequest request = DataRequest.newBuilder()
                .setQueryId(queryId)
                .setQuery(filename)
                .build();

        logger.info("Starting download - queryId: {}, filename: {}", queryId, filename);

        asyncStub.downloadFile(request, new StreamObserver<DataResponse>() {
            private OutputStream outputStream;
            private long totalBytesReceived = 0;

            @Override
            public void onNext(DataResponse response) {
                try {
                    if ("FILE_NOT_FOUND".equals(response.getStatus())) {
                        logger.error("File not found: {}", filename);
                        return;
                    }

                    if ("ERROR".equals(response.getStatus())) {
                        logger.error("Download error: {}", response.getStatus());
                        return;
                    }

                    if (outputStream == null) {
                        outputStream = new BufferedOutputStream(new FileOutputStream(outputPath));
                    }

                    byte[] data = response.getPayload().toByteArray();
                    outputStream.write(data);
                    totalBytesReceived += data.length;

                    logger.debug("Received chunk #{}: {} bytes (total: {})",
                            response.getSequenceNumber(), data.length, totalBytesReceived);

                } catch (IOException e) {
                    logger.error("Error writing downloaded data", e);
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.error("Download stream error", t);
                closeStream();
                latch.countDown();
            }

            @Override
            public void onCompleted() {
                closeStream();
                logger.info("Download completed. Total bytes received: {}", totalBytesReceived);
                latch.countDown();
            }

            private void closeStream() {
                if (outputStream != null) {
                    try {
                        outputStream.flush();
                        outputStream.close();
                    } catch (IOException e) {
                        logger.error("Error closing output stream", e);
                    }
                }
            }
        });

        if (!latch.await(10, TimeUnit.MINUTES)) {
            logger.warn("Download timed out");
        }
    }

    // Bidirectional streaming - process data
    public void processDataBidirectional(String sessionId) throws InterruptedException {
        CountDownLatch latch = new CountDownLatch(1);

        StreamObserver<ProcessingMessage> responseObserver = new StreamObserver<ProcessingMessage>() {
            @Override
            public void onNext(ProcessingMessage message) {
                logger.info("Received response - session: {}, type: {}, size: {} bytes, headers: {}",
                        message.getSessionId(), message.getMessageType(),
                        message.getData().size(), message.getHeadersMap());
            }

            @Override
            public void onError(Throwable t) {
                logger.error("Bidirectional stream error", t);
                latch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info("Bidirectional stream completed for session: {}", sessionId);
                latch.countDown();
            }
        };

        StreamObserver<ProcessingMessage> requestObserver = asyncStub.processData(responseObserver);

        try {
            // Send a PING
            requestObserver.onNext(ProcessingMessage.newBuilder()
                    .setSessionId(sessionId)
                    .setMessageType("PING")
                    .setTimestamp(System.currentTimeMillis())
                    .build());

            Thread.sleep(100);

            // Send a TRANSFORM request
            byte[] sampleData = "Hello, this is sample data for transformation!".getBytes();
            requestObserver.onNext(ProcessingMessage.newBuilder()
                    .setSessionId(sessionId)
                    .setMessageType("TRANSFORM")
                    .setData(ByteString.copyFrom(sampleData))
                    .setTimestamp(System.currentTimeMillis())
                    .putHeaders("encoding", "utf-8")
                    .build());

            Thread.sleep(100);

            // Send an AGGREGATE request
            byte[] numericData = new byte[1000];
            for (int i = 0; i < numericData.length; i++) {
                numericData[i] = (byte) (i % 256);
            }
            requestObserver.onNext(ProcessingMessage.newBuilder()
                    .setSessionId(sessionId)
                    .setMessageType("AGGREGATE")
                    .setData(ByteString.copyFrom(numericData))
                    .setTimestamp(System.currentTimeMillis())
                    .build());

            Thread.sleep(100);

            // Send a FILTER request
            requestObserver.onNext(ProcessingMessage.newBuilder()
                    .setSessionId(sessionId)
                    .setMessageType("FILTER")
                    .setData(ByteString.copyFrom(numericData))
                    .setTimestamp(System.currentTimeMillis())
                    .putHeaders("threshold", "200")
                    .build());

            Thread.sleep(100);

            requestObserver.onCompleted();

        } catch (Exception e) {
            requestObserver.onError(e);
            throw e;
        }

        if (!latch.await(1, TimeUnit.MINUTES)) {
            logger.warn("Bidirectional processing timed out");
        }
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(5, TimeUnit.SECONDS);
    }

    public static void main(String[] args) throws Exception {
        FileServiceClient client = new FileServiceClient("localhost", 9090);

        try {
            // Example: Upload a file
            if (args.length > 0 && "upload".equals(args[0]) && args.length > 1) {
                client.uploadFile(args[1]);
            }

            // Example: Download a file
            if (args.length > 0 && "download".equals(args[0]) && args.length > 2) {
                client.downloadFile("query-001", args[1], args[2]);
            }

            // Example: Bidirectional processing
            if (args.length == 0 || "process".equals(args[0])) {
                client.processDataBidirectional("session-" + System.currentTimeMillis());
            }

        } finally {
            client.shutdown();
        }
    }
}